    const heap = [];

    // Sort elements by value in descending order
    const sorted = value.map((v, i) => [v, i]).sort((a, b) => b[0] - a[0]);

    // Use a priority queue (min-heap) to track the active elements by limit
    const minHeap = new MinHeap((a, b) => a[1] - b[1]);

